from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    from collections import defaultdict

    # Helper to join multiple objects with commas and 'and'
    def join_objs(objs: list[str]) -> str:
        if not objs:
            return ""
        if len(objs) == 1:
            return objs[0]
        return ", ".join(objs[:-1]) + " and " + objs[-1]

    # Mapping from predicate to a phrase builder
    # pre‑compute a lookup of all triples for easy cross‑reference
    subject_pred_map = defaultdict(list)  # type: dict[tuple[str, str], list[str]]
    for t in triples:
        subject_pred_map[(t.subject, t.predicate)].append(t.object)

    def build_phrase(subject: str, pred: str, objs: list[str]) -> str:
        # Helper to find objects of a given subject/predicate elsewhere in the data
        def lookup(other_subj: str, other_pred: str) -> list[str]:
            return subject_pred_map.get((other_subj, other_pred), [])

        if pred == "birthDate":
            return f"was born on {objs[0]}"
        if pred in ("birthYear", "birthPlace"):
            return f"was born in {objs[0]}"
        if pred == "origin":
            if len(objs) == 1:
                return f"originates from {objs[0]}"
            else:
                return f"originates from {join_objs(objs)}"
        if pred == "genre":
            # Expect only one genre per subject for simplicity
            genre_obj = objs[0]
            # Check if this genre has a derivative relationship
            derivative_objs = lookup(genre_obj, "derivative")
            if derivative_objs:
                return f"{subject}'s genre is {genre_obj} which is derived from {join_objs(derivative_objs)}"
            # Check for musicFusionGenre as well
            fusion_objs = lookup(genre_obj, "musicFusionGenre")
            if fusion_objs:
                return f"{subject}'s genre is {genre_obj} and it fuses with {join_objs(fusion_objs)}"
            return f"{subject}'s genre is {genre_obj}"
        if pred == "instrument":
            return f"plays the {join_objs(objs)}"
        if pred == "occupation":
            return f"is a {join_objs(objs)}"
        if pred == "nationality":
            return f"is {join_objs(objs)}"
        if pred == "associatedBand/associatedMusicalArtist":
            # Use a more natural verb for band membership
            return f"plays with {join_objs(objs)}"
        if pred == "recordLabel":
            return f"is signed to {join_objs(objs)}"
        if pred == "activeYearsStartYear":
            return f"started their career in {join_objs(objs)}"
        if pred == "activeYearsEndYear":
            return f"ended their career in {join_objs(objs)}"
        if pred == "deathDate":
            return f"died on {join_objs(objs)}"
        if pred == "deathPlace":
            return f"died in {join_objs(objs)}"
        if pred == "alternativeName":
            return f"is also known as {join_objs(objs)}"
        if pred == "stylisticOrigin":
            return f"has its stylistic origins in {join_objs(objs)}"
        if pred == "musicFusionGenre":
            return f"has a fusion genre {join_objs(objs)}"
        if pred == "derivative":
            return f"is a derivative of {join_objs(objs)}"
        # fallback
        return f"{pred} {join_objs(objs)}"

    # Group objects by (subject, predicate)
    groups = defaultdict(list)  # type: dict[tuple[str, str], list[str]]
    for t in triples:
        groups[(t.subject, t.predicate)].append(t.object)

    main_subject = triples[0].subject
    sentences = []

    # Build sentence for the main subject aggregating its predicates
    main_clauses = []
    for (sub, pred), objs in groups.items():
        if sub != main_subject:
            continue
        phrase = build_phrase(sub, pred, objs)
        if phrase:
            main_clauses.append(phrase)

    if main_clauses:
        main_sentence = f"{main_subject} " + ", ".join(main_clauses) + "."
        sentences.append(main_sentence[0].upper() + main_sentence[1:])

    # Build separate sentences for other subjects
    for (sub, pred), objs in groups.items():
        if sub == main_subject:
            continue
        phrase = build_phrase(sub, pred, objs)
        if phrase:
            other_sentence = f"{phrase}."
            sentences.append(other_sentence[0].upper() + other_sentence[1:])

    return " ".join(sentences)

# EVOLVE-BLOCK-END

